#include<bits/stdc++.h>
using namespace std;
int fa[100010];
int find(int x)
{
    return (x==fa[x]?x:fa[x]=find(fa[x]));
}
void merge(int x,int y)
{
    fa[find(x)]=find(y);
}
struct node
{
    int u,v,w;
    bool operator<(const node&b)const
    {
        return w>b.w;
    }
}a[100010];
int main()
{
    int n,k;
    scanf("%d%d",&n,&k);
    long long sum=0;
    for(int i=1;i<=n+1;i++)
    {
        fa[i]=i;
    }
    for(int i=1;i<=k;i++)
    {
        int x;
        scanf("%d",&x);
        x++;
        fa[x]=n+1;
    }
    for(int i=1;i<n;i++)
    {
        scanf("%d%d%d",&a[i].u,&a[i].v,&a[i].w);
        a[i].u++;
        a[i].v++;
        sum+=a[i].w;
    }
    sort(a+1,a+n);
    long long ans=0;
    for(int i=1;i<n;i++)
    {
        if(find(a[i].u)!=find(a[i].v))
        {
            merge(a[i].u,a[i].v);
            ans+=a[i].w;
        }
    }
    printf("%lld",sum-ans);
    return 0;
}
